section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/spatial-design-tools.json",
  "title": "Spatial Design Tools",
  "type": "object",
  "required": [
    "artefact_id",
    "report_id",
    "tools_evaluated",
    "selected_stack",
    "handoff_pipeline",
    "license_map",
    "ownership",
    "evidence",
    "review_cadence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "report_id": {
      "type": "string",
      "description": "report_id",
      "minLength": 1
    },
    "tools_evaluated": {
      "type": "array",
      "description": "tools_evaluated (array)",
      "minItems": 1
    },
    "selected_stack": {
      "type": "string",
      "description": "selected_stack",
      "minLength": 1
    },
    "handoff_pipeline": {
      "type": "string",
      "description": "handoff_pipeline",
      "minLength": 1
    },
    "license_map": {
      "type": "string",
      "description": "license_map",
      "minLength": 1
    },
    "ownership": {
      "type": "string",
      "description": "ownership",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "review_cadence": {
      "type": "string",
      "description": "review_cadence",
      "minLength": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
